/**
 * @summary Get the next unannotated post for a coder
 */
export const getGetNextPostToAnnotateUrl = (
  params: GetNextPostToAnnotateParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/posts/next-to-annotate?${stringifiedParams}`
    : `/api/posts/next-to-annotate`;
};

export const getNextPostToAnnotate = async (
  params: GetNextPostToAnnotateParams,
  options?: RequestInit,
): Promise<Post> => {
  return customFetch<Post>(getGetNextPostToAnnotateUrl(params), {
    ...options,
    method: "GET",
  });
};

